import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic();

function detectParallelRedundancy(response: any): boolean {
  const toolUses = response.content.filter((block: any) => block.type === 'tool_use');

  if (toolUses.length < 2) return false;

  const toolInputs = toolUses.map((tu: any) => JSON.stringify(tu.input));
  const uniqueInputs = new Set(toolInputs);

  return uniqueInputs.size < toolUses.length;
}
